import{_ as e,o as a,c as i,ae as o}from"./chunks/framework.C4hbK2lm.js";const s="/Web_Lecture/assets/in1.A-Xuxb32.png",l="/Web_Lecture/assets/in2.u0APUfVS.png",d="/Web_Lecture/assets/in3.DNZ-ZM3o.png",p="/Web_Lecture/assets/Internet_Explorer_6.DwvSdGKl.png",r="/Web_Lecture/assets/jap.tI7G_A-j.png",n="/Web_Lecture/assets/jap2.CAGM4lve.png",c="/Web_Lecture/assets/terminal.CKXGGrGx.jpg",h="/Web_Lecture/assets/wsl1.D0rp3n0s.png",u="/Web_Lecture/assets/wsl2.CUn0VSVe.png",b="/Web_Lecture/assets/command.BF8Gkqrx.png",g="/Web_Lecture/assets/update.CgGQdlIT.png",f=JSON.parse('{"title":"KCS Web班へようこそ！","description":"","frontmatter":{"marp":true,"header":"Web班へようこそ！","footer":"2026 KCS Web班","paginate":true},"headers":[],"relativePath":"../Web_Lecture/environment/env.md","filePath":"../Web_Lecture/environment/env.md"}'),m={name:"../Web_Lecture/environment/env.md"};function k(_,t,C,v,W,S){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="kcs-web班へようこそ" tabindex="-1">KCS Web班へようこそ！ <a class="header-anchor" href="#kcs-web班へようこそ" aria-label="Permalink to &quot;KCS Web班へようこそ！&quot;">​</a></h1><p>KCS :: Keio Computer Society は、慶應義塾大学で唯一、そして日本最古のコンピュータサークルです。「パソコン使って全部やる」をモットーに、Web・AI・System（低レイヤー）・競プロ・ゲーム・音楽・CG の７班に分かれて活動しています。</p><p>本記事は、2026年度 Web班の講習会資料です。</p><hr><h1 id="目次" tabindex="-1">目次 <a class="header-anchor" href="#目次" aria-label="Permalink to &quot;目次&quot;">​</a></h1><hr><ol><li><p><strong>自己紹介</strong></p></li><li><p><strong>Web班について</strong></p><p>2-1. 活動のモチベ</p><p>2-2. 活動内容</p></li><li><p><strong>Web概論</strong></p></li><li><p><strong>開発環境の構築</strong></p><p>4-1. Visual Studio Code とは</p><p>4-2. インストール・環境構築</p><p>4-3. VSCode ショートカットキーまとめ</p></li><li><p><strong>CLI に慣れる</strong></p><p>5-1. GUI と CLI</p><p>5-2. コマンドはどこで打つ？</p><p>5-3. bash系が主流</p><p>5-4. WSLの環境構築（Windowsの方向け）</p><p>5-5. 基本的なLinuxコマンド</p><p>5-6. Web開発でよく使うコマンドのインストール</p></li></ol><hr><h2 id="_1-自己紹介" tabindex="-1">1. 自己紹介 <a class="header-anchor" href="#_1-自己紹介" aria-label="Permalink to &quot;1. 自己紹介&quot;">​</a></h2><p><img src="'+s+'" alt="in1"></p><p><img src="'+l+'" alt="in2"></p><p><img src="'+d+'" alt="in3"></p><hr><h2 id="_2-web班について" tabindex="-1">2. Web班について <a class="header-anchor" href="#_2-web班について" aria-label="Permalink to &quot;2. Web班について&quot;">​</a></h2><h2 id="_2-1-活動のモチベ" tabindex="-1">2-1. 活動のモチベ <a class="header-anchor" href="#_2-1-活動のモチベ" aria-label="Permalink to &quot;2-1. 活動のモチベ&quot;">​</a></h2><p>IT業界は、次のように大別されます。</p><blockquote><ul><li>インターネット/Web（ポータルサイト、ショッピングサイト、SNS）</li><li>ソフトウェア（業務アプリ、OS、ミドルウェア）</li><li>ハードウェア（PC、スマホ、ネットワーク機器、半導体）</li><li>通信インフラ（通信キャリア、ISP）</li><li>情報処理サービス（ITコンサルタント）</li></ul></blockquote><p>また、エンジニアの種類には、</p><blockquote><ul><li>開発系 <ul><li>フロントエンドエンジニア</li><li>バックエンド（サーバーサイド）エンジニア</li><li>システムエンジニア</li></ul></li><li>インフラ系 <ul><li>ネットワークエンジニア</li><li>サーバーエンジニア</li><li>セキュリティエンジニア</li></ul></li><li>コンサル/マネジメント系 <ul><li>プロジェクトマネージャー</li><li>ITコンサルタント</li></ul></li></ul></blockquote><p>のようなものがあります。</p><p>エンジニアとして働きたい、という漠然とした思いからプログラミングを学び始めると、私も含め、多くの人が次のような壁にぶつかります。</p><ul><li><p>インターンなどで実務経験を積みたい</p></li><li><p>しかし大手企業のインターンに参加するには、ある程度の実務経験が求められる</p></li><li><p>一方でベンチャー企業のインターンは、教育体制が十分でない場合もある</p></li><li><p>Web開発を独学しようとしても、何から手をつければよいのかわからない</p></li></ul><p>そこで、エンジニアを目指し始めて同じ悩みを抱える方が、Web開発の基礎を体系的に学び、その後スムーズに実務経験のステップへとつなげていけるよう、本記事を執筆しています。</p><p>また、「今はAIがWebサイトを簡単に作ってくれるのに、わざわざWeb開発を学ぶ意味はあるのか？」という疑問に関しては、</p><ul><li><p>仕組みを学ぶことで、より良い実装、迅速なデバッグができる</p></li><li><p>AIに的確な指示を出せる（使われる側ではなく、使う側に回る）</p></li><li><p>上流工程（システムの設計、方向性の決定）で現実的な判断ができるようになる</p></li><li><p>作ること自体が楽しい</p></li></ul><p>という理由で、学ぶ意義は十分にあると考えます。</p><p>私自身もまだ学習中の立場ですが、だからこそ同じ目線で、役立つ情報をまとめていければと思っています。</p><p>Web班のみんなで知見を共有しあえたら嬉しいです！！（・ω・　）ﾌｧ</p><h2 id="_2-2-活動内容" tabindex="-1">2-2. 活動内容 <a class="header-anchor" href="#_2-2-活動内容" aria-label="Permalink to &quot;2-2. 活動内容&quot;">​</a></h2><ol><li><p><strong>開発環境の構築</strong> ◀︎</p></li><li><p><strong>フロントエンド入門</strong> - おみくじを作る（HTML, CSS, JavaScript）</p></li><li><p><strong>フロントエンド実践</strong> - ポートフォリオを作る（Next.js, React）</p></li><li><p><strong>Git/GitHub講習</strong></p></li><li><p><strong>バックエンド入門1</strong> - ログイン機能を作る（PHP）</p></li><li><p><strong>バックエンド入門2</strong> - 掲示板を作る（PHP, SQL）</p></li><li><p><strong>Docker講習</strong></p></li><li><p><strong>バックエンド実践</strong> - 掲示板を作る（FastAPI）</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>ここまで終えたあたりで、エンジニアの長期インターンに参加してみるのがオススメです。KCSの先輩が紹介してくださいます！</p></div><p>（ここからは動的に決めます。<strong>太字</strong>は絶対やりたい）</p><ul><li><strong>チーム開発</strong>（去年は三田祭サイトを開発した。もっと本格的なWebサービスを作るのも良き。アイデア募集中）</li><li><strong>バックエンドの発展的な技術</strong>（キャッシュで高速化、WebSocketでゲーム作る、etc...）</li><li><strong>アーキテクチャ、ソフトウェア工学</strong></li><li><strong>Webデザイン</strong>（UI/UXを学ぶ、CSSを完全に理解する）</li><li>デプロイ体験</li><li>色んなWebフレームワークを触ってみる</li><li>Webセキュリティ（DevSecOpsを考える、CTFで脆弱性を学ぶ）</li><li>自作ブラウザ（そろそろSystem班になってきてまずい）</li></ul><hr><h2 id="_3-web概論" tabindex="-1">3. Web概論 <a class="header-anchor" href="#_3-web概論" aria-label="Permalink to &quot;3. Web概論&quot;">​</a></h2><p>Webとは、Wordle Wide Web の略（世界規模のクモの巣）。インターネット上の情報をブラウザで見る仕組みのこと。</p><h3 id="ブラウザの歴史" tabindex="-1">ブラウザの歴史 <a class="header-anchor" href="#ブラウザの歴史" aria-label="Permalink to &quot;ブラウザの歴史&quot;">​</a></h3><p>ブラウザとは、URLを入力することでサーバからWebページを取得し、それを解釈し、表示するソフトウェア。</p><ol><li><p>WorldWideWeb（1990）</p><p>人類初のブラウザ。</p></li><li><p><strong>Internet Explorer</strong>（1995）</p><p>Microsoft社がWindowsに標準搭載し、2000年前後の主流となった。</p><p><img src="'+p+'" alt="ie"></p></li><li><p><strong>Safari</strong>（2003）</p><p>Apple社がMacに標準搭載した。iPhone（2007）とともに普及。</p></li><li><p><strong>Firefox</strong>（2004）</p><p>Mozilla Corporation社が開発。ブラウザの「タブ」という概念が生まれた。</p></li><li><p><strong>Google Chrome</strong>（2008）</p><p>超高速、安定。現在の主流。</p></li><li><p><strong>Microsoft Edge</strong>（2015）</p><p>IE の後継。2020年に、Chromiumベースに変更された。</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>Chromium</strong></p><p>Google社がオープンソースとして公開した、ブラウザを作る土台。Google Chrome や Microsoft Edge の内部で使われている。</p></div><hr><hr><p>Webの導入はここまでです！</p><p>次章から、実践的な内容に入ります。頑張っていきましょう！</p><hr><h2 id="_4-開発環境の構築" tabindex="-1">4. 開発環境の構築 <a class="header-anchor" href="#_4-開発環境の構築" aria-label="Permalink to &quot;4. 開発環境の構築&quot;">​</a></h2><h2 id="_4-1-visual-studio-code-とは" tabindex="-1">4-1. Visual Studio Code とは <a class="header-anchor" href="#_4-1-visual-studio-code-とは" aria-label="Permalink to &quot;4-1. Visual Studio Code とは&quot;">​</a></h2><p>Web開発時は、Microsoftが提供する無料のソースコードエディタ「Visual Studio Code」を利用する。</p><p>エディタ、ターミナル、Git関連ツール、デバッガ、コード補完など、快適な開発環境を提供してくれる。</p><h2 id="_4-2-インストール・環境構築" tabindex="-1">4-2. インストール・環境構築 <a class="header-anchor" href="#_4-2-インストール・環境構築" aria-label="Permalink to &quot;4-2. インストール・環境構築&quot;">​</a></h2><ol><li><p><a href="https://code.visualstudio.com/Download" target="_blank" rel="noreferrer">https://code.visualstudio.com/Download</a></p><p>から、自分のOSに合わせてインストーラーをダウンロード</p></li><li><p>インストーラーを実行し、指示に従ってインストール</p></li></ol><h3 id="日本語にする-任意" tabindex="-1">日本語にする（任意） <a class="header-anchor" href="#日本語にする-任意" aria-label="Permalink to &quot;日本語にする（任意）&quot;">​</a></h3><ol><li><p>拡張機能（左バーの一番下）で <code>Japanese Language Pack</code> と検索</p><p><img src="'+r+'" alt="jap1"></p></li><li><p>インストールし、VSCode を再起動</p><p><img src="'+n+`" alt="jap2"></p></li></ol><h3 id="コード整形してくれるやつ" tabindex="-1">コード整形してくれるやつ <a class="header-anchor" href="#コード整形してくれるやつ" aria-label="Permalink to &quot;コード整形してくれるやつ&quot;">​</a></h3><ol><li><p>拡張機能 &gt; <code>Prettier - Code formatter</code> をインストール</p></li><li><p><code>Cmd + Shift + P</code> で、<code>setting.json</code>と入力し、「ユーザー設定を開く（JSON）」を選択</p></li><li><p>開いたファイルに、下記を入力</p><div class="language-JSON vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">JSON</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;editor.formatOnSave&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;editor.defaultFormatter&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;esbenp.prettier-vscode&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div></li></ol><hr><h2 id="_4-3-vscode-ショートカットキーまとめ" tabindex="-1">4-3. VSCode ショートカットキーまとめ <a class="header-anchor" href="#_4-3-vscode-ショートカットキーまとめ" aria-label="Permalink to &quot;4-3. VSCode ショートカットキーまとめ&quot;">​</a></h2><p>最初の3個だけ覚えれば大丈夫！</p><table tabindex="0"><thead><tr><th>操作内容</th><th>Windows / Linux</th><th>Mac</th></tr></thead><tbody><tr><td><strong>ファイル保存</strong></td><td><code>Ctrl + S</code></td><td><code>Cmd + S</code></td></tr><tr><td><strong>元に戻す（Undo）</strong></td><td><code>Ctrl + Z</code></td><td><code>Cmd + Z</code></td></tr><tr><td><strong>Undoを元に戻す（Redo）</strong></td><td><code>Ctrl + Y</code> / <code>Ctrl + Shift + Z</code></td><td><code>Cmd + Shift + Z</code></td></tr><tr><td>全選択</td><td><code>Ctrl + A</code></td><td><code>Cmd + A</code></td></tr><tr><td>コマンドパレット</td><td><code>Ctrl + Shift + P</code></td><td><code>Cmd + Shift + P</code></td></tr><tr><td>ファイル/ディレクトリを開く</td><td><code>Ctrl + O</code></td><td><code>Cmd + O</code></td></tr><tr><td>新規ファイル作成</td><td><code>Ctrl + N</code></td><td><code>Cmd + N</code></td></tr><tr><td>ページ内検索</td><td><code>Ctrl + Shift + F</code></td><td><code>Cmd + Shift + F</code></td></tr><tr><td>ページ内検索＋置換</td><td><code>Ctrl + Shift + H</code></td><td><code>Cmd + Shift + H</code></td></tr></tbody></table><hr><h2 id="_5-cli-に慣れる" tabindex="-1">5. CLI に慣れる <a class="header-anchor" href="#_5-cli-に慣れる" aria-label="Permalink to &quot;5. CLI に慣れる&quot;">​</a></h2><h2 id="_5-1-gui-と-cli" tabindex="-1">5-1. GUI と CLI <a class="header-anchor" href="#_5-1-gui-と-cli" aria-label="Permalink to &quot;5-1. GUI と CLI&quot;">​</a></h2><p>画面操作ではなく文字で、コンピュータに命令をする。シンプルに便利。</p><ul><li><p><strong>GUI</strong>（Graphical User Interface）</p><p>ボタンをクリックしたり、アイコンをドラッグしたりして、画面操作する。</p></li><li><p><strong>CLI</strong>（Command Line Interface）</p><p>上記の操作を、文章（コマンド）で行う。</p><p>ex.) <code>$ mkdir test &amp;&amp; cd test</code>＝ testフォルダを作ってそこに移動する</p></li></ul><h2 id="_5-2-コマンドはどこで打つ" tabindex="-1">5-2. コマンドはどこで打つ？ <a class="header-anchor" href="#_5-2-コマンドはどこで打つ" aria-label="Permalink to &quot;5-2. コマンドはどこで打つ？&quot;">​</a></h2><p><img src="`+c+'" alt="term"></p><ol><li><p>Linux / Mac</p><p>ターミナル（シェルは bash / zsh）。</p></li><li><p>Windows</p><p>コマンドプロンプト（cmd.exe）、PowerShellなど。</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>シェル</strong></p><p>ユーザーが入力したコマンドを解釈し、コンピュータに伝える（仲介する）プログラム。</p><p>OSによってシェルが異なり、コマンドの文法も異なる。</p></div><h2 id="_5-3-bash系が主流" tabindex="-1">5-3. bash系が主流 <a class="header-anchor" href="#_5-3-bash系が主流" aria-label="Permalink to &quot;5-3. bash系が主流&quot;">​</a></h2><p>実際の開発や本番環境では、Linux（bash系のシェル）が基準。</p><ul><li><p>Mac</p><p>ターミナルの中で動いている zsh は bash の後継。</p></li><li><p>Windows</p><p><strong>WSL</strong>（Windows Subsystem for Linux）を入れる。LinuxOS を、Windows 上で実行できるようにする、軽量な仮想環境。</p></li></ul><h2 id="_5-4-wslの環境構築-windowsの方向け" tabindex="-1">5-4. WSLの環境構築（Windowsの方向け） <a class="header-anchor" href="#_5-4-wslの環境構築-windowsの方向け" aria-label="Permalink to &quot;5-4. WSLの環境構築（Windowsの方向け）&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>以降に出てくる <code>$ ...</code> は、<code>$</code> を含めず、文章のみをコピペして入力してください！</p></div><ol><li><p>コマンドプロンプトを<strong>管理者として</strong>開く（アプリのアイコンを右クリック）</p></li><li><p>wsl のインストール</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wsl --install</span></span></code></pre></div><p><img src="'+h+'" alt="wsl1"></p></li><li><p>Windows を再起動</p></li><li><p>コマンドプロンプトを開き、以下を実行</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wsl --set-default-version 2</span></span></code></pre></div></li><li><p>Ubuntu ユーザの設定</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ wsl --install -d Ubuntu</span></span></code></pre></div><p><img src="'+u+'" alt="wsl2"></p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>ここで設定した ユーザ名 / パスワード を忘れずに！</p></div></li><li><p>今後は、コマンドプロンプトで <code>$ wsl</code> を実行し、Linux 環境で開発を行う。</p></li></ol><h2 id="_5-5-基本的なlinuxコマンド" tabindex="-1">5-5. 基本的なLinuxコマンド <a class="header-anchor" href="#_5-5-基本的なlinuxコマンド" aria-label="Permalink to &quot;5-5. 基本的なLinuxコマンド&quot;">​</a></h2><table tabindex="0"><thead><tr><th>コマンド</th><th>意味</th><th>使用例</th><th>説明</th></tr></thead><tbody><tr><td><code>ls</code></td><td>ファイル一覧表示</td><td><code>ls -la</code></td><td>ディレクトリの中身を見る</td></tr><tr><td><code>cd</code></td><td>ディレクトリ移動</td><td><code>cd /home/user</code></td><td>フォルダを移動する</td></tr><tr><td><code>pwd</code></td><td>現在地表示</td><td><code>pwd</code></td><td>今いるディレクトリを確認</td></tr><tr><td><code>cp</code></td><td>コピー</td><td><code>cp a.txt b.txt</code></td><td>ファイルをコピー</td></tr><tr><td><code>mv</code></td><td>移動 / 名前変更</td><td><code>mv a.txt b.txt</code></td><td>ファイル移動 or リネーム</td></tr><tr><td><code>rm</code></td><td>削除</td><td><code>rm file.txt</code></td><td>ファイルを削除</td></tr><tr><td><code>cat</code></td><td>中身表示</td><td><code>cat file.txt</code></td><td>ファイルの内容を表示</td></tr></tbody></table><p>Windowsの方はコマンドプロンプト&gt;<code>wsl</code>で、Macの方はターミナルで、CLI操作に慣れましょう。</p><p><img src="'+b+'" alt="command"></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>情報工学科2年の「コンピュータ実習」の授業で学びます！</p></div><h2 id="_5-6-web開発でよく使うコマンドのインストール" tabindex="-1">5-6. Web開発でよく使うコマンドのインストール <a class="header-anchor" href="#_5-6-web開発でよく使うコマンドのインストール" aria-label="Permalink to &quot;5-6. Web開発でよく使うコマンドのインストール&quot;">​</a></h2><h3 id="パッケージ管理の更新" tabindex="-1">パッケージ管理の更新 <a class="header-anchor" href="#パッケージ管理の更新" aria-label="Permalink to &quot;パッケージ管理の更新&quot;">​</a></h3><p>（WSL）<code>$ sudo apt update &amp;&amp; sudo apt upgrade -y</code></p><p>（Mac）<code>$ brew update &amp;&amp; brew upgrade</code></p><p><img src="'+g+'" alt="update"></p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>WSLの <code>password for xxx</code> には、2-4で設定したWSLユーザのパスワードを入力する。Macは、ログイン時に使用しているパスワード。</p></div><h3 id="node-js-環境構築" tabindex="-1">Node.js 環境構築 <a class="header-anchor" href="#node-js-環境構築" aria-label="Permalink to &quot;Node.js 環境構築&quot;">​</a></h3><p>Web開発でよく使う言語はJavaScript。</p><p>これを使えるように、<strong>Node.js</strong>（＝ JavaScript実行環境）を入れる。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>JavaScriptの実行には V8エンジン が必要で、ブラウザやNode.jsがそれを持っている。</p></div><ol><li><p>nvm（Nodeの管理）のインストール</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ curl -o- https://raw.githubusercontent.com/nvm-sh/nvm/v0.39.7/install.sh | bash</span></span></code></pre></div></li><li><p>シェルの設定ファイル（<code>~/.bashrc</code>, <code>~/.zshrc</code>）を読み直して反映</p><p>（WSL）<code>$ source ~/.bashrc</code></p><p>（Mac）<code>$ source ~/.zshrc</code></p><p>または、ターミナルの再起動</p></li><li><p>Node.js のインストール</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ nvm install --lts</span></span></code></pre></div></li></ol><hr><h2 id="お疲れさまでした" tabindex="-1">お疲れさまでした！ <a class="header-anchor" href="#お疲れさまでした" aria-label="Permalink to &quot;お疲れさまでした！&quot;">​</a></h2><p>次回以降は、基本的なコードの書き方やWebの知識を学んでいきます。</p><p>興味のある言語やフレームワークを調べて触ってみたり、どんなサービスを作りたいか考えてみたりして、Discord でいろいろ共有しあいましょう！</p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li>WIKINEWS <a href="https://en.wikinews.org/wiki/File%3AInternet_Explorer_6.png" target="_blank" rel="noreferrer">File:Internet Explorer 6.png</a></li></ul>',96)])])}const q=e(m,[["render",k]]);export{f as __pageData,q as default};
